package runtime

import "testing"

func TestReadinessDefaultsNotReady(t *testing.T) {
	readiness := NewReadiness()

	if readiness.Ready() {
		t.Fatalf("expected new readiness gate to start not ready")
	}
}

func TestReadinessTransitions(t *testing.T) {
	readiness := NewReadiness()

	readiness.MarkReady()
	if !readiness.Ready() {
		t.Fatalf("expected readiness gate to report ready after MarkReady")
	}

	readiness.MarkNotReady()
	if readiness.Ready() {
		t.Fatalf("expected readiness gate to report not ready after MarkNotReady")
	}
}

package migration_test

import (
	"testing"
	"time"

	"socialpredict/migration"
	"socialpredict/models/modelstesting"

	"gorm.io/gorm"
)

// Migration tests use SQLite-backed modelstesting helpers as fast package-local
// convenience coverage for registry ordering, idempotency, and fail-closed
// checks. They are not source-of-truth evidence for W04 migration serialization,
// advisory locking, or single-writer startup behavior on real Postgres.

func TestRegister_DuplicateReturnsError(t *testing.T) {
	migration.ClearRegistry()

	err := migration.Register("20250101000000", func(db *gorm.DB) error { return nil })
	if err != nil {
		t.Fatalf("first registration should succeed, got error: %v", err)
	}

	// Second registration with the same ID should return error.
	err = migration.Register("20250101000000", func(db *gorm.DB) error { return nil })
	if err == nil {
		t.Fatalf("expected error on duplicate migration id, got none")
	}

	expectedMsg := "duplicate migration id: 20250101000000"
	if err.Error() != expectedMsg {
		t.Fatalf("expected error message %q, got %q", expectedMsg, err.Error())
	}
}

func TestRun_AppliesInOrder_And_Persists(t *testing.T) {
	migration.ClearRegistry()
	db := modelstesting.NewTestDB(t)

	var calls []string

	// Register intentionally out of order; Run must apply in ascending lexicographic order.
	if err := migration.Register("20250103000000", func(db *gorm.DB) error {
		calls = append(calls, "20250103000000")
		// Touch DB to ensure Up() runs a real operation
		return db.AutoMigrate(&migration.SchemaMigration{})
	}); err != nil {
		t.Fatalf("Register: %v", err)
	}
	if err := migration.Register("20250101000000", func(db *gorm.DB) error {
		calls = append(calls, "20250101000000")
		return nil
	}); err != nil {
		t.Fatalf("Register: %v", err)
	}
	if err := migration.Register("20250102000000", func(db *gorm.DB) error {
		calls = append(calls, "20250102000000")
		return nil
	}); err != nil {
		t.Fatalf("Register: %v", err)
	}

	if err := migration.Run(db); err != nil {
		t.Fatalf("Run: %v", err)
	}

	want := []string{"20250101000000", "20250102000000", "20250103000000"}
	if len(calls) != len(want) {
		t.Fatalf("unexpected call count: got %d want %d", len(calls), len(want))
	}
	for i := range want {
		if calls[i] != want[i] {
			t.Fatalf("order[%d]: got %s want %s", i, calls[i], want[i])
		}
	}

	var rows []migration.SchemaMigration
	if err := db.Order("id asc").Find(&rows).Error; err != nil {
		t.Fatalf("query SchemaMigration: %v", err)
	}
	if len(rows) != 3 {
		t.Fatalf("expected 3 SchemaMigration rows, got %d", len(rows))
	}
	for i := range want {
		if rows[i].ID != want[i] {
			t.Fatalf("row[%d].ID: got %s want %s", i, rows[i].ID, want[i])
		}
		if rows[i].AppliedAt.IsZero() {
			t.Fatalf("row[%d].AppliedAt is zero", i)
		}
	}
}

func TestRun_IsIdempotent(t *testing.T) {
	migration.ClearRegistry()
	db := modelstesting.NewTestDB(t)

	var calls []string
	if err := migration.Register("20250101000000", func(db *gorm.DB) error {
		calls = append(calls, "20250101000000")
		return nil
	}); err != nil {
		t.Fatalf("Register: %v", err)
	}

	// First run applies once.
	if err := migration.Run(db); err != nil {
		t.Fatalf("Run (first): %v", err)
	}
	if len(calls) != 1 {
		t.Fatalf("after first run, calls=%d want 1", len(calls))
	}

	// Second run should skip already-applied migration.
	if err := migration.Run(db); err != nil {
		t.Fatalf("Run (second): %v", err)
	}
	if len(calls) != 1 {
		t.Fatalf("after second run, calls=%d want 1 (idempotent)", len(calls))
	}

	var rows []migration.SchemaMigration
	if err := db.Find(&rows).Error; err != nil {
		t.Fatalf("query SchemaMigration: %v", err)
	}
	if len(rows) != 1 || rows[0].ID != "20250101000000" {
		t.Fatalf("unexpected SchemaMigration state: %+v", rows)
	}
}

func TestRun_ErrOnNilUp(t *testing.T) {
	migration.ClearRegistry()
	db := modelstesting.NewTestDB(t)

	if err := migration.Register("20250102000000", nil); err != nil {
		t.Fatalf("Register: %v", err)
	}

	if err := migration.Run(db); err == nil {
		t.Fatalf("expected error for nil Up(), got nil")
	}
}

func TestRun_PersistsAppliedAt(t *testing.T) {
	migration.ClearRegistry()
	db := modelstesting.NewTestDB(t)

	if err := migration.Register("20250104000000", func(db *gorm.DB) error { return nil }); err != nil {
		t.Fatalf("Register: %v", err)
	}

	if err := migration.Run(db); err != nil {
		t.Fatalf("Run: %v", err)
	}

	var row migration.SchemaMigration
	if err := db.First(&row, "id = ?", "20250104000000").Error; err != nil {
		t.Fatalf("lookup SchemaMigration: %v", err)
	}
	if row.AppliedAt.IsZero() || time.Since(row.AppliedAt) < 0 {
		t.Fatalf("AppliedAt not set correctly: %+v", row)
	}
}

func TestMigrateDBErrorsWhenNoMigrationsRegistered(t *testing.T) {
	migration.ClearRegistry()
	db := modelstesting.NewTestDB(t)

	if err := migration.MigrateDB(db); err == nil {
		t.Fatalf("expected no registered migrations to fail closed")
	}
}

func TestVerifyAppliedRequiresAllRegisteredMigrations(t *testing.T) {
	migration.ClearRegistry()
	db := modelstesting.NewTestDB(t)

	if err := migration.Register("20250101000000", func(db *gorm.DB) error { return nil }); err != nil {
		t.Fatalf("Register: %v", err)
	}
	if err := migration.Register("20250102000000", func(db *gorm.DB) error { return nil }); err != nil {
		t.Fatalf("Register: %v", err)
	}

	if err := migration.Run(db); err != nil {
		t.Fatalf("Run: %v", err)
	}
	if err := migration.VerifyApplied(db); err != nil {
		t.Fatalf("VerifyApplied after Run: %v", err)
	}

	if err := db.Delete(&migration.SchemaMigration{}, "id = ?", "20250102000000").Error; err != nil {
		t.Fatalf("delete SchemaMigration: %v", err)
	}
	if err := migration.VerifyApplied(db); err == nil {
		t.Fatalf("expected missing registered migration to fail verification")
	}
}

func TestVerifyAppliedDoesNotCreateSchemaMigrationTable(t *testing.T) {
	migration.ClearRegistry()
	db := modelstesting.NewTestDB(t)

	if err := migration.Register("20250101000000", func(db *gorm.DB) error { return nil }); err != nil {
		t.Fatalf("Register: %v", err)
	}

	if err := migration.VerifyApplied(db); err == nil {
		t.Fatalf("expected missing schema migrations table to fail verification")
	}
	if db.Migrator().HasTable(&migration.SchemaMigration{}) {
		t.Fatalf("VerifyApplied must not create schema migrations table")
	}
}

package runtime

import (
	"os"
	"testing"
)

// Startup mutation tests validate the local fail-closed mode selection only.
// They do not prove multi-replica migration or seed serialization; that W04
// startup-writer risk still requires real-Postgres verification once the
// locking or leader mechanism is chosen.

func TestLoadStartupMutationModeDefaultsToNonWriter(t *testing.T) {
	unsetEnvForTest(t, StartupWriterEnv)
	unsetEnvForTest(t, legacyStartupWriterEnv)

	mode, err := LoadStartupMutationModeFromEnv()
	if err != nil {
		t.Fatalf("LoadStartupMutationModeFromEnv returned error: %v", err)
	}
	if mode.Writer {
		t.Fatalf("expected default startup mutation mode to be non-writer")
	}
	if mode.Source != "default" {
		t.Fatalf("expected default startup mutation source, got %q", mode.Source)
	}
}

func TestLoadStartupMutationModePrimaryFlagTakesPrecedence(t *testing.T) {
	t.Setenv(StartupWriterEnv, "0")
	t.Setenv(legacyStartupWriterEnv, "true")

	mode, err := LoadStartupMutationModeFromEnv()
	if err != nil {
		t.Fatalf("LoadStartupMutationModeFromEnv returned error: %v", err)
	}
	if mode.Writer {
		t.Fatalf("expected explicit false startup writer flag to disable writer mode")
	}
	if mode.Source != StartupWriterEnv {
		t.Fatalf("expected primary startup writer env source, got %q", mode.Source)
	}
}

func TestLoadStartupMutationModeUsesLegacyWhenPrimaryMissing(t *testing.T) {
	t.Setenv(legacyStartupWriterEnv, "true")

	mode, err := LoadStartupMutationModeFromEnv()
	if err != nil {
		t.Fatalf("LoadStartupMutationModeFromEnv returned error: %v", err)
	}
	if !mode.Writer {
		t.Fatalf("expected legacy startup writer flag to enable writer mode")
	}
	if mode.Source != legacyStartupWriterEnv {
		t.Fatalf("expected legacy startup writer env source, got %q", mode.Source)
	}
}

func TestLoadStartupMutationModeRejectsInvalidFlag(t *testing.T) {
	t.Setenv(StartupWriterEnv, "sometimes")

	if _, err := LoadStartupMutationModeFromEnv(); err == nil {
		t.Fatalf("expected invalid startup writer flag to fail closed")
	}
}

func unsetEnvForTest(t *testing.T, key string) {
	t.Helper()

	original, existed := os.LookupEnv(key)
	if err := os.Unsetenv(key); err != nil {
		t.Fatalf("Unsetenv(%s): %v", key, err)
	}
	t.Cleanup(func() {
		if existed {
			if err := os.Setenv(key, original); err != nil {
				t.Fatalf("Setenv(%s): %v", key, err)
			}
			return
		}
		if err := os.Unsetenv(key); err != nil {
			t.Fatalf("Unsetenv(%s): %v", key, err)
		}
	})
}

package runtime

import (
	"context"
	"fmt"
	"log"
	"os"
	"strconv"
	"strings"
	"sync"
	"time"

	"gorm.io/driver/postgres"
	"gorm.io/gorm"
	gormlogger "gorm.io/gorm/logger"
)

var (
	db   *gorm.DB
	dbMu sync.RWMutex
)

// DBConfig holds the normalized database configuration.
type DBConfig struct {
	Host     string
	Port     string
	User     string
	Password string
	Name     string
	SSLMode  string
	TimeZone string

	MaxOpenConns    int
	MaxIdleConns    int
	ConnMaxLifetime time.Duration
	ConnMaxIdleTime time.Duration
	RequireTLS      bool
}

// DBFactory provides a hook to open a database using a given configuration.
type DBFactory interface {
	Open(DBConfig) (*gorm.DB, error)
}

// PostgresFactory implements DBFactory using the postgres driver.
type PostgresFactory struct {
	GormConfig *gorm.Config
}

// LoadDBConfigFromEnv normalizes env vars into a DBConfig.
func LoadDBConfigFromEnv() (DBConfig, error) {
	cfg := DBConfig{
		Host:            firstNonEmpty(os.Getenv("DB_HOST"), os.Getenv("DBHOST")),
		User:            firstNonEmpty(os.Getenv("POSTGRES_USER"), os.Getenv("DB_USER")),
		Password:        firstNonEmpty(os.Getenv("POSTGRES_PASSWORD"), os.Getenv("DB_PASS"), os.Getenv("DB_PASSWORD")),
		Name:            firstNonEmpty(os.Getenv("POSTGRES_DATABASE"), os.Getenv("POSTGRES_DB"), os.Getenv("DB_NAME")),
		Port:            firstNonEmpty(os.Getenv("POSTGRES_PORT"), os.Getenv("DB_PORT"), "5432"),
		SSLMode:         firstNonEmpty(os.Getenv("DB_SSLMODE"), os.Getenv("POSTGRES_SSLMODE"), os.Getenv("PGSSLMODE"), "disable"),
		TimeZone:        firstNonEmpty(os.Getenv("DB_TIMEZONE"), os.Getenv("PGTZ"), "UTC"),
		MaxOpenConns:    intFromEnv(25, "DB_MAX_OPEN_CONNS", "POSTGRES_MAX_OPEN_CONNS"),
		MaxIdleConns:    intFromEnv(5, "DB_MAX_IDLE_CONNS", "POSTGRES_MAX_IDLE_CONNS"),
		ConnMaxLifetime: durationFromEnv(30*time.Minute, "DB_CONN_MAX_LIFETIME", "POSTGRES_CONN_MAX_LIFETIME"),
		ConnMaxIdleTime: durationFromEnv(5*time.Minute, "DB_CONN_MAX_IDLE_TIME", "POSTGRES_CONN_MAX_IDLE_TIME"),
		RequireTLS:      boolFromEnv(isProductionRuntime(), "DB_REQUIRE_TLS", "POSTGRES_REQUIRE_TLS"),
	}

	if cfg.Host == "" {
		return DBConfig{}, fmt.Errorf("missing DB host (DB_HOST or DBHOST)")
	}
	if cfg.User == "" {
		return DBConfig{}, fmt.Errorf("missing DB user (POSTGRES_USER or DB_USER)")
	}
	if cfg.Name == "" {
		return DBConfig{}, fmt.Errorf("missing DB name (POSTGRES_DATABASE/POSTGRES_DB/DB_NAME)")
	}

	return cfg, nil
}

// BuildPostgresDSN assembles the postgres DSN from config.
func BuildPostgresDSN(cfg DBConfig) (string, error) {
	cfg.Host = strings.TrimSpace(cfg.Host)
	cfg.User = strings.TrimSpace(cfg.User)
	cfg.Name = strings.TrimSpace(cfg.Name)
	cfg.Port = strings.TrimSpace(cfg.Port)
	cfg.SSLMode = strings.ToLower(strings.TrimSpace(cfg.SSLMode))
	cfg.TimeZone = strings.TrimSpace(cfg.TimeZone)

	if cfg.Host == "" || cfg.User == "" || cfg.Name == "" {
		return "", fmt.Errorf("invalid DB config: host/user/name required")
	}

	port := cfg.Port
	if port == "" {
		port = "5432"
	}

	sslMode := cfg.SSLMode
	if sslMode == "" {
		sslMode = "disable"
	}
	if err := validateSSLMode(sslMode, cfg.RequireTLS); err != nil {
		return "", err
	}

	timeZone := cfg.TimeZone
	if timeZone == "" {
		timeZone = "UTC"
	}

	dsn := fmt.Sprintf(
		"host=%s user=%s password=%s dbname=%s port=%s sslmode=%s TimeZone=%s",
		cfg.Host,
		cfg.User,
		cfg.Password,
		cfg.Name,
		port,
		sslMode,
		timeZone,
	)

	return dsn, nil
}

// Open opens a postgres-backed gorm DB using the provided configuration.
func (f PostgresFactory) Open(cfg DBConfig) (*gorm.DB, error) {
	dsn, err := BuildPostgresDSN(cfg)
	if err != nil {
		return nil, err
	}

	gormCfg := f.GormConfig
	if gormCfg == nil {
		gormCfg = &gorm.Config{}
	}

	if gormCfg.Logger == nil {
		gormCfg.Logger = newFilteredGormLogger(gormlogger.New(
			log.New(os.Stdout, "\r\n", log.LstdFlags),
			gormlogger.Config{
				LogLevel:                  gormlogger.Warn,
				IgnoreRecordNotFoundError: true,
			},
		))
	}

	return gorm.Open(postgres.Open(dsn), gormCfg)
}

// InitDB opens the explicit runtime DB handle with the provided factory and config.
func InitDB(cfg DBConfig, factory DBFactory) (*gorm.DB, error) {
	if factory == nil {
		factory = PostgresFactory{}
	}

	conn, err := factory.Open(cfg)
	if err != nil {
		return nil, fmt.Errorf("open db: %w", err)
	}
	if conn == nil {
		return nil, fmt.Errorf("open db: factory returned nil db")
	}
	if err := ConfigureDBPool(conn, cfg); err != nil {
		return nil, fmt.Errorf("configure db pool: %w", err)
	}
	return conn, nil
}

// ConfigureDBPool applies runtime-owned connection pool and lifetime policy.
func ConfigureDBPool(db *gorm.DB, cfg DBConfig) error {
	if db == nil {
		return fmt.Errorf("database handle unavailable")
	}

	sqlDB, err := db.DB()
	if err != nil {
		return fmt.Errorf("sql db handle unavailable: %w", err)
	}

	sqlDB.SetMaxOpenConns(normalizeNonNegative(cfg.MaxOpenConns))
	sqlDB.SetMaxIdleConns(normalizeNonNegative(cfg.MaxIdleConns))
	sqlDB.SetConnMaxLifetime(normalizeNonNegativeDuration(cfg.ConnMaxLifetime))
	sqlDB.SetConnMaxIdleTime(normalizeNonNegativeDuration(cfg.ConnMaxIdleTime))
	return nil
}

// CheckDBReadiness verifies that the backing SQL connection is reachable for request handling.
func CheckDBReadiness(ctx context.Context, db *gorm.DB) error {
	if db == nil {
		return fmt.Errorf("database handle unavailable")
	}
	if ctx == nil {
		ctx = context.Background()
	}

	sqlDB, err := db.DB()
	if err != nil {
		return fmt.Errorf("sql db handle unavailable: %w", err)
	}
	if err := sqlDB.PingContext(ctx); err != nil {
		return fmt.Errorf("database ping failed: %w", err)
	}

	return nil
}

// CloseDB closes the underlying SQL connection pool during runtime shutdown.
func CloseDB(db *gorm.DB) error {
	if db == nil {
		return nil
	}

	sqlDB, err := db.DB()
	if err != nil {
		return fmt.Errorf("sql db handle unavailable: %w", err)
	}
	if err := sqlDB.Close(); err != nil {
		return fmt.Errorf("close db: %w", err)
	}
	return nil
}

// SetDB stores a process-global handle for legacy tests and narrow migration bridges.
//
// Production startup should pass the DB handle explicitly from InitDB instead of using
// this fallback.
func SetDB(conn *gorm.DB) {
	dbMu.Lock()
	db = conn
	dbMu.Unlock()
}

// GetDB returns the legacy process-global database connection.
//
// Production startup should pass the DB handle explicitly from InitDB instead of using
// this fallback.
func GetDB() *gorm.DB {
	dbMu.RLock()
	defer dbMu.RUnlock()
	return db
}

func firstNonEmpty(values ...string) string {
	for _, v := range values {
		if trimmed := strings.TrimSpace(v); trimmed != "" {
			return trimmed
		}
	}
	return ""
}

func intFromEnv(defaultValue int, keys ...string) int {
	value := firstExistingEnv(keys...)
	if value == "" {
		return defaultValue
	}
	parsed, err := strconv.Atoi(value)
	if err != nil {
		return defaultValue
	}
	return parsed
}

func durationFromEnv(defaultValue time.Duration, keys ...string) time.Duration {
	value := firstExistingEnv(keys...)
	if value == "" {
		return defaultValue
	}
	parsed, err := time.ParseDuration(value)
	if err != nil {
		return defaultValue
	}
	return parsed
}

func boolFromEnv(defaultValue bool, keys ...string) bool {
	value := strings.ToLower(firstExistingEnv(keys...))
