package migration

import (
	"fmt"
	"sort"
	"time"

	"gorm.io/gorm"
	"socialpredict/logger"
)

// Registry of migrations; you already have tests that exercise this.
var registry = map[string]func(*gorm.DB) error{}

type SchemaMigration struct {
	ID        string    `gorm:"primaryKey;size:32"`
	AppliedAt time.Time `gorm:"autoCreateTime"`
}

func Register(id string, up func(*gorm.DB) error) error {
	if _, exists := registry[id]; exists {
		return fmt.Errorf("duplicate migration id: %s", id)
	}
	registry[id] = up
	return nil
}

func ClearRegistry() { // used by tests
	for k := range registry {
		delete(registry, k)
	}
}

// Run applies registered migrations in ID order and records them.
func Run(db *gorm.DB) error {
	if len(registry) == 0 {
		return fmt.Errorf("no registered migrations found")
	}
	if err := ensureSchemaTable(db); err != nil {
		return err
	}

	applied, err := loadAppliedMigrations(db)
	if err != nil {
		return err
	}

	for _, id := range sortedRegistryIDs() {
		if applied[id] {
			continue
		}
		if err := applyMigration(db, id); err != nil {
			return err
		}
	}
	return nil
}

// VerifyApplied confirms that all registered migrations have already been
// recorded without mutating the schema. Request-serving startup paths use this
// when they are not the explicit startup writer.
func VerifyApplied(db *gorm.DB) error {
	if len(registry) == 0 {
		return fmt.Errorf("no registered migrations found")
	}
	if !db.Migrator().HasTable(&SchemaMigration{}) {
		return fmt.Errorf("schema migrations table is missing")
	}

	applied, err := loadAppliedMigrations(db)
	if err != nil {
		return err
	}

	for _, id := range sortedRegistryIDs() {
		if !applied[id] {
			return fmt.Errorf("registered migration %s has not been applied", id)
		}
	}
	return nil
}

func ensureSchemaTable(db *gorm.DB) error {
	if err := db.AutoMigrate(&SchemaMigration{}); err != nil {
		return fmt.Errorf("auto-migrate SchemaMigration: %w", err)
	}
	return nil
}

func loadAppliedMigrations(db *gorm.DB) (map[string]bool, error) {
	applied := map[string]bool{}
	var rows []SchemaMigration
	if err := db.Find(&rows).Error; err != nil {
		return nil, fmt.Errorf("load SchemaMigration: %w", err)
	}
	for _, r := range rows {
		applied[r.ID] = true
	}
	return applied, nil
}

func sortedRegistryIDs() []string {
	ids := make([]string, 0, len(registry))
	for id := range registry {
		ids = append(ids, id)
	}
	sort.Strings(ids)
	return ids
}

func applyMigration(db *gorm.DB, id string) error {
	up := registry[id]
	if up == nil {
		return fmt.Errorf("migration %s has nil Up()", id)
	}
	if err := up(db); err != nil {
		return fmt.Errorf("migration %s failed: %w", id, err)
	}
	if err := db.Create(&SchemaMigration{ID: id, AppliedAt: time.Now()}).Error; err != nil {
		return fmt.Errorf("record SchemaMigration %s: %w", id, err)
	}
	return nil
}

// MigrateDB is the public entry for explicit startup writers.
func MigrateDB(db *gorm.DB) error {
	logger.LogInfo("Migration", "MigrateDB", "starting database migrations")

	if len(registry) == 0 {
		return fmt.Errorf("no registered migrations found")
	}

	if err := Run(db); err != nil {
		return err
	}

	logger.LogInfo("Migration", "MigrateDB", "database migrations completed")
	return nil
}

package server

import (
	"bytes"
	"encoding/json"
	"net/http"
	"net/http/httptest"
	"strings"
	"testing"

	"socialpredict/handlers"
	appruntime "socialpredict/internal/app/runtime"
	"socialpredict/models"
	"socialpredict/models/modelstesting"
)

func TestServerServesOpenAPIDocumentAndSwaggerRedirect(t *testing.T) {
	t.Setenv("JWT_SIGNING_KEY", "test-secret-key")

	db := modelstesting.NewFakeDB(t)
	handler := buildTestHandler(t, db)

	openAPIReq := httptest.NewRequest(http.MethodGet, "/openapi.yaml", nil)
	openAPIRec := httptest.NewRecorder()
	handler.ServeHTTP(openAPIRec, openAPIReq)

	if openAPIRec.Code != http.StatusOK {
		t.Fatalf("expected status 200, got %d: %s", openAPIRec.Code, openAPIRec.Body.String())
	}
	if got := openAPIRec.Header().Get("Content-Type"); !strings.HasPrefix(got, "application/yaml") {
		t.Fatalf("expected yaml content type, got %q", got)
	}
	if !strings.Contains(openAPIRec.Body.String(), "openapi:") {
		t.Fatalf("expected OpenAPI body, got %q", openAPIRec.Body.String())
	}

	swaggerRedirectReq := httptest.NewRequest(http.MethodGet, "/swagger", nil)
	swaggerRedirectRec := httptest.NewRecorder()
	handler.ServeHTTP(swaggerRedirectRec, swaggerRedirectReq)

	if swaggerRedirectRec.Code != http.StatusMovedPermanently {
		t.Fatalf("expected swagger redirect status 301, got %d", swaggerRedirectRec.Code)
	}
	if location := swaggerRedirectRec.Header().Get("Location"); location != "/swagger/" {
		t.Fatalf("expected redirect to /swagger/, got %q", location)
	}

	swaggerReq := httptest.NewRequest(http.MethodGet, "/swagger/", nil)
	swaggerRec := httptest.NewRecorder()
	handler.ServeHTTP(swaggerRec, swaggerReq)

	if swaggerRec.Code != http.StatusOK {
		t.Fatalf("expected swagger status 200, got %d", swaggerRec.Code)
	}
	if !strings.Contains(swaggerRec.Body.String(), "swagger") {
		t.Fatalf("expected swagger placeholder body, got %q", swaggerRec.Body.String())
	}

	for _, path := range []string{"/swagger", "/swagger/"} {
		t.Run("method not allowed "+path, func(t *testing.T) {
			req := httptest.NewRequest(http.MethodPost, path, nil)
			rec := httptest.NewRecorder()
			handler.ServeHTTP(rec, req)

			if rec.Code != http.StatusMethodNotAllowed {
				t.Fatalf("expected swagger POST status 405, got %d: %s", rec.Code, rec.Body.String())
			}
			var response handlers.FailureEnvelope
			if err := json.Unmarshal(rec.Body.Bytes(), &response); err != nil {
				t.Fatalf("decode swagger method failure: %v", err)
			}
			if response.OK || response.Reason != string(handlers.ReasonMethodNotAllowed) {
				t.Fatalf("expected reason %q, got %+v", handlers.ReasonMethodNotAllowed, response)
			}
		})
	}
}

