package runtime

import (
	"context"
	"testing"

	"socialpredict/models/modelstesting"
)

// ServingProbe tests deliberately keep the readiness gate package-local and
// SQLite-backed. They are convenience coverage for liveness/readiness wiring;
// W04 still needs real-Postgres proof for readiness behavior against the
// production driver and database outage modes.

func TestServingProbeLivenessIsIndependentOfReadiness(t *testing.T) {
	probe := NewServingProbe(nil, nil)

	if !probe.Live() {
		t.Fatalf("expected serving probe to report live process")
	}
}

func TestServingProbeReadinessRequiresStartupGateAndDatabase(t *testing.T) {
	ctx := context.Background()
	db := modelstesting.NewFakeDB(t)
	readiness := NewReadiness()
	probe := NewServingProbe(db, readiness)

	if err := probe.Ready(ctx); err == nil {
		t.Fatalf("expected readiness to fail while startup gate is closed")
	}

	readiness.MarkReady()
	if err := probe.Ready(ctx); err != nil {
		t.Fatalf("expected readiness to pass with open startup gate and reachable database: %v", err)
	}

	sqlDB, err := db.DB()
	if err != nil {
		t.Fatalf("db.DB: %v", err)
	}
	if err := sqlDB.Close(); err != nil {
		t.Fatalf("close sql db: %v", err)
	}
	if err := probe.Ready(ctx); err == nil {
		t.Fatalf("expected readiness to fail when database is unavailable")
	}
}

	req := httptest.NewRequest(http.MethodGet, "/readyz", nil)
	rec := httptest.NewRecorder()
	handler.ServeHTTP(rec, req)

	if rec.Code != http.StatusServiceUnavailable {
		t.Fatalf("expected /readyz status 503 while startup gate is closed, got %d", rec.Code)
	}
	if got := rec.Header().Get("Content-Type"); got != "text/plain; charset=utf-8" {
		t.Fatalf("expected /readyz PlainTextErrorResponse content type, got %q", got)
	}
	if body := rec.Body.String(); body != "not ready" {
		t.Fatalf("expected /readyz PlainTextErrorResponse body not ready, got %q", body)
	}
}

package runtime

import (
	"context"
	"testing"
	"time"

	"socialpredict/models/modelstesting"

	"gorm.io/gorm"
)

// These runtime DB tests use fake handles or SQLite-backed modelstesting helpers
// for fast package-local coverage. They prove config, handle ownership, and
// basic ping/close behavior, but real Postgres remains the source of truth for
// W04 readiness under DB loss, pool/lifetime behavior, SSL posture, and HA
// startup semantics.

func TestInitDBReturnsExplicitHandleWithoutSharedFallback(t *testing.T) {
	original := GetDB()
	t.Cleanup(func() {
		SetDB(original)
	})

	want := modelstesting.NewFakeDB(t)
	legacy := modelstesting.NewFakeDB(t)
	SetDB(legacy)
	factory := stubFactory{db: want}

	got, err := InitDB(DBConfig{
		Host:            "localhost",
		User:            "postgres",
		Name:            "socialpredict",
		MaxOpenConns:    12,
		MaxIdleConns:    4,
		ConnMaxLifetime: time.Hour,
		ConnMaxIdleTime: 10 * time.Minute,
	}, factory)
	if err != nil {
		t.Fatalf("InitDB returned error: %v", err)
	}

	if got != want {
		t.Fatalf("expected InitDB to return factory db")
	}
	if shared := GetDB(); shared != legacy {
		t.Fatalf("expected InitDB not to replace shared db handle")
	}

	sqlDB, err := got.DB()
	if err != nil {
		t.Fatalf("db.DB: %v", err)
	}
	stats := sqlDB.Stats()
	if stats.MaxOpenConnections != 12 {
		t.Fatalf("expected max open connections to be configured, got %d", stats.MaxOpenConnections)
	}
}

